#!/usr/bin/env bash
# portrait-posing-direction.sh — 人像引导与摆姿 (Portrait Posing & Direction) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="人像引导与摆姿 (Portrait Posing & Direction)"

usage() {
  cat <<EOF
portrait-posing-direction.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./portrait-posing-direction.sh             # interactive
  ./portrait-posing-direction.sh --dry-run
  ./portrait-posing-direction.sh --json
  ./portrait-posing-direction.sh --explain
  ./portrait-posing-direction.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "人像引导与摆姿 (Portrait Posing & Direction)" 工作流。

一句话: 把镜头前僵硬紧张的真人，引导成自然、有表情、体态显瘦的状态——决定人像「像不像个人」的软技能闭环。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**建立 rapport**: 开拍前聊几句、解释流程、降低紧张，让对方信任。跳过 → 对方全程僵硬，表情假笑或木讷，再好的光也救不了。(evidence: [T03-S006])"
  "**先摆身体再调脸**: 先定身体角度（三七侧身 30–45° 最显瘦），再转头/脸找角度。跳过顺序 → 正面平拍显胖、姿势别扭。(evidence: [T03-S006])"
  "**下巴/肩线管理**: 「下巴前伸略下压」（Peter Hurley 的「乌龟」/ Sue Bryce「chin forward and down」）定义下颌线、消除双下巴；肩膀主动下沉后拉去紧张。跳过 → 双下巴、耸肩、脖子缩。(evidence: [T03-S006])"
  "**手脚处理**: 给手一个「任务」（扶、插兜、碰头发），脚分重心避免直挺挺。跳过 → 手不知放哪显尴尬，全身重心呆板。"
  "**表情管理 + 引导**: 实拍中持续给指令/逗笑/给情绪，抓自然表情而非「茄子」。跳过 → 一组假笑或呆滞，无可用表情。(evidence: [T03-S006])"
)
declare -a FAILURE_MODES=(
  "**不建立 rapport 直接开拍**: 对方紧张僵硬假笑 → 先聊 2 分钟、解释流程再举机。**CLI 自检**: 「你和被摄者建立信任了吗，还是冷场直接拍？」"
  "**先调脸再摆身体**: 顺序反了导致姿势别扭 → 永远先定身体角度再转脸。"
  "**忘了下巴/肩线**: 出现双下巴、耸肩 → 每个机位提醒「下巴前伸下压、肩膀沉下去」。**CLI 自检**: 「下巴前伸略下压了吗？肩膀放松下沉了吗？」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "portrait-posing-direction-walkthrough"
fi
